import{j as e,r as s}from"./vendor-DGA4RRtu.js";const r=[{id:"scale_1",number:"01",title:"The Physical Fabric",quote:"Before the observer, there was only the architecture of existence. The literal mechanics of matter, energy, and spacetime operate in a domain unburdened by psychological time.",subjects:[{title:"Mathematics",rationale:"The absolute, structural language of objective reality functioning without semantic labeling or egoic distortion. It is the purest expression of deterministic truth, existing independently of human observation.",inquiry_nodes:["How does mathematical truth exist independently of human observation and the biological mechanism of perception?","Does the concept of probability merely reflect the limits of human processing, pointing toward an absolute, underlying determinism?"]},{title:"Physics",rationale:"The literal mechanics of matter, energy, and spacetime; the unfiltered ruleset of the macro and micro before biological perception intercepts it. The 'speed', 'distance', and 'time' here are objective realities.",inquiry_nodes:["Does the observer effect in quantum mechanics parallel the Default Mode Network's distortion of reality through the act of perception?","How does time function as a strictly physical dimension in contrast to the psychological illusion of time created by the ego's desire to 'become'?"]},{title:"Chemistry",rationale:"The combinatorial logic of elements operating just below the threshold where matter organizes into biological survival mechanisms. It demonstrates a deterministic interplay of bonds, devoid of choice.",inquiry_nodes:["At what exact molecular threshold does deterministic 'matter' begin to exhibit the biological drive for homeostasis?","How does the absolute predictability of chemical bonds challenge the human cognitive construct of choice?"]}]},{id:"scale_2",number:"02",title:"The Biological Matrix",quote:"The organic machinery driven by the necessity of survival. It is here that the physical drive for continuity is born, a mechanism tragically misapplied by the human brain to create the illusion of psychological permanence.",subjects:[{title:"Biology",rationale:"The study of the organic machinery driven by survival, revealing the cellular basis of fear and reward pathways. This exact physical mechanism of survival is what the human mind misapplies to defend its psychological self-image.",inquiry_nodes:["How does the biological drive for physiological homeostasis create the foundation for psychological resistance to 'what is'?","Can the cellular mechanics of fear be entirely separated from the psychological narrative of suffering?"]},{title:"Zoology & Botany",rationale:"The observation of the biological matrix adapting in real-time without the burden of psychological time. Flora and fauna operate in pure, non-semantic intelligence, reacting to environmental facts without egoic resistance.",inquiry_nodes:["What can the non-semantic intelligence of fauna teach us about action devoid of the psychological 'Doer'?","Is the decentralized intelligence of an ecosystem a truer reflection of universal mechanics than centralized human cognition?"]}]},{id:"scale_3",number:"03",title:"The Cognitive Architecture",quote:"The internal software processing reality. It is the domain where pure observation is fractured by semantic labeling, giving rise to the observer, the observed, and the illusion of distance.",subjects:[{title:"Neuroscience",rationale:"The literal, physical mapping of the Ego, viewing the 'mind' not as an abstract entity but as the Default Mode Network running a continuous loop of conditioning. It provides empirical proof that the 'Self' is a pattern of information processing.",inquiry_nodes:["Can the subjective experience of 'Ego death' be empirically mapped as the temporary suspension of the Default Mode Network?","How does the physiological structure of the brain sustain the continuous loop of psychological suffering?"]},{title:"Psychology",rationale:"The objective observation of conditioning and how past memory distorts present perception. It analyzes the paradox of effort—how the brain's attempt to 'control' its state only sustains the neural loop it seeks to escape.",inquiry_nodes:["How does the brain's categorization engine create the illusion of distance between the observer and the observed?","What are the mechanical limits of introspection when the entity analyzing the thought is itself a product of thought?"]},{title:"Linguistics",rationale:"The study of the semantic labeling mechanism that fragments reality. By naming something, the brain ceases to observe the living fact, and grammar structures physically program the mind to perceive a dualistic, fragmented reality.",inquiry_nodes:["What is the precise limitation of the 'Word' in experiencing the choiceless reality of 'what is'?","How do subject-verb-object grammatical structures physically wire the brain to enforce the illusion of a separate 'Doer'?"]}]},{id:"scale_4",number:"04",title:"The Human Construct",quote:"The mechanics of civilization. These are the macro-structures built collectively by the human mind to manage fear, secure biological survival, and organize collective egoic desires.",subjects:[{title:"Sociology",rationale:"The study of collective cognitive biases and herd mentality, observing how individual egos aggregate to form shared neural conditioning. Society provides artificial psychological security to alleviate the fear of isolation.",inquiry_nodes:["To what extent is a 'society' simply an aggregation of individual egos seeking shared psychological security?","What are the mechanics of group identity, and how does collective conditioning override objective perception?"]},{title:"History",rationale:"The neurological document of the Ego in action across time. It is the tragic, repetitive record of conflict and the illusion of 'becoming', proving that external revolutions fail while inner architecture remains tribal.",inquiry_nodes:["Why does the fundamental pattern of human conflict repeat endlessly, regardless of the overarching ideology?","How does the study of history reveal the continuous movement of the conditioned past polluting the present moment?"]},{title:"Geography",rationale:"The physical manifestation of the Default Mode Network's 'Us vs. Them' mechanism. Borders are not natural phenomena; they are psychological constructs drawn to enforce separation and secure resources.",inquiry_nodes:["How do national borders function as macro-level psychological constructs driven by the biological fear of scarcity?","What is the neurological relationship between a physical environment and the cognitive conditioning of its population?"]},{title:"Political Science",rationale:"The observation of macro-structures built to organize collective egoic desires. Power is viewed fundamentally as a symptom of deep psychological insecurity, not as a systemic solution.",inquiry_nodes:["How does the pursuit of political power serve as a macroscopic symptom of an individual's psychological insecurity?","What is the illusion behind applying ideological solutions to problems rooted entirely in the mechanics of human cognition?"]},{title:"Economics",rationale:"The materialization of the biological dopamine reward pathway. Greed is viewed as a neurological malfunction—an infinite loop demanding repetition—driving the Ego's attempt to find permanence through accumulation.",inquiry_nodes:["In what ways is the concept of economic 'value' entirely a shared cognitive illusion?","How can greed be deconstructed as a malfunction of the dopamine pathway rather than a failure of moral character?"]},{title:"Computer Science & AI",rationale:"The externalized mirror of human information processing. By building AI, humanity is mapping its own cognitive architecture, forcing us to ask if the 'Ego' itself is merely an operating system.",inquiry_nodes:["As artificial neural networks grow, can they simulate the anxieties and self-referential loops of the Default Mode Network?","If the human 'Ego' is viewed as an operating system, what does the architecture of AI reveal about our own conditioning?"]}]},{id:"scale_5",number:"05",title:"The Synthesis",quote:"The ultimate merger. This is the collapse of distance between the observer and the observed, where semantic labeling ceases, and reality is perceived in its choiceless, unbroken whole.",subjects:[{title:"Philosophy",rationale:"Not the exercise of abstract theorizing, but the literal, objective perception of reality without the interference of the observer. It rigorously deconstructs the illusion of free will, leading to choiceless awareness.",inquiry_nodes:["What are the precise mechanics of choiceless awareness when the Default Mode Network is suspended?","How does the profound realization of deterministic universal mechanics naturally deconstruct the illusion of free will?"]},{title:"Literature",rationale:"The documentation of the human condition and the tragedy of the divided mind. It exposes the narrative arc of conflict and resolution as a direct reflection of humanity's entrapment in psychological time.",inquiry_nodes:["How does the traditional narrative arc serve as a direct reflection of humanity's entrapment in psychological time?","Can ancient mythology be decoded as early, intuitive attempts to map the inner cognitive architecture?"]},{title:"Fine Arts",rationale:"Attempts to express the unbroken whole of reality beyond semantic constraints. True aesthetic experience is the brief suspension of the Default Mode Network, where the distance between observer and art collapses.",inquiry_nodes:["Can profound aesthetic experiences be empirically measured as the temporary silencing of the brain's self-referential narratives?","Is it possible for art to bypass ingrained psychological conditioning to trigger a state of direct, unmediated perception?"]}]}],l=({subject:t})=>{const[i,o]=s.useState(!1);return e.jsxs("div",{className:"border border-slate-700 rounded-lg bg-slate-800/50 mb-4 overflow-hidden transition-all duration-300",children:[e.jsxs("button",{onClick:()=>o(!i),className:"w-full flex justify-between items-center p-5 text-left focus:outline-none hover:bg-slate-800 transition-colors",children:[e.jsx("span",{className:"text-lg font-semibold text-slate-100",children:t.title}),e.jsx("svg",{className:`w-5 h-5 text-teal-500 transform transition-transform duration-300 ${i?"rotate-180":""}`,fill:"none",stroke:"currentColor",viewBox:"0 0 24 24",children:e.jsx("path",{strokeLinecap:"round",strokeLinejoin:"round",strokeWidth:2,d:"M19 9l-7 7-7-7"})})]}),e.jsx("div",{className:`transition-all duration-300 ease-in-out ${i?"max-h-[1000px] opacity-100":"max-h-0 opacity-0"} overflow-hidden`,children:e.jsxs("div",{className:"p-5 pt-0",children:[e.jsxs("blockquote",{className:"border-l-4 border-teal-500 bg-slate-900/50 text-slate-300 p-4 mb-5 rounded-r-lg italic leading-relaxed",children:['"',t.rationale,'"']}),e.jsxs("div",{className:"px-2",children:[e.jsx("h4",{className:"text-xs font-bold uppercase tracking-widest text-teal-600 mb-3",children:"Inquiry Nodes"}),e.jsx("ul",{className:"space-y-3",children:t.inquiry_nodes.map((a,n)=>e.jsxs("li",{className:"flex items-start text-sm text-slate-400",children:[e.jsx("span",{className:"text-teal-500 mr-2 mt-0.5",children:"•"}),e.jsx("span",{className:"leading-relaxed",children:a})]},n))})]})]})})]})};function h(){return e.jsxs("div",{className:"min-h-screen bg-slate-900 font-sans selection:bg-teal-500 selection:text-white pb-24",children:[e.jsxs("div",{className:"relative pt-32 pb-20 px-6 sm:px-10 lg:px-20 overflow-hidden border-b border-slate-800",children:[e.jsx("div",{className:"absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-800 via-slate-900 to-slate-900 pointer-events-none"}),e.jsx("div",{className:"absolute top-0 right-0 w-[600px] h-[600px] bg-teal-600/10 rounded-full blur-[120px] pointer-events-none mix-blend-screen"}),e.jsxs("div",{className:"max-w-4xl mx-auto relative z-10",children:[e.jsx("span",{className:"inline-block py-1 px-3 rounded-full bg-teal-500/10 border border-teal-500/20 text-teal-400 text-xs font-bold uppercase tracking-[0.2em] mb-6",children:"Core Philosophy"}),e.jsx("h1",{className:"text-5xl md:text-7xl font-black text-white tracking-tight leading-none mb-6",children:"The Knowledge Tree."}),e.jsx("p",{className:"text-lg md:text-xl text-slate-400 max-w-2xl leading-relaxed font-light",children:"A comprehensive mapping of reality, moving from the macro physical laws to the micro architecture of human cognition. We deconstruct existence—merging scientific mechanics with objective philosophical observation."})]})]}),e.jsx("div",{className:"max-w-4xl mx-auto px-6 sm:px-10 mt-20",children:e.jsx("div",{className:"relative border-l border-slate-800 ml-4 md:ml-8",children:r.map(t=>e.jsxs("div",{className:"mb-24 relative pl-8 md:pl-16 group",children:[e.jsx("div",{className:"absolute -left-4 md:-left-6 top-1 flex items-center justify-center w-8 h-8 md:w-12 md:h-12 rounded-full bg-slate-900 border-2 border-teal-500 text-teal-400 font-bold text-xs md:text-sm transition-colors group-hover:bg-teal-500 group-hover:text-slate-900 shadow-[0_0_15px_rgba(20,184,166,0.3)]",children:t.number}),e.jsxs("div",{className:"mb-10 pt-1 md:pt-2",children:[e.jsx("h2",{className:"text-3xl md:text-4xl font-bold text-slate-100 mb-6 tracking-tight",children:t.title}),e.jsx("div",{className:"text-slate-400 text-base md:text-lg italic font-light leading-relaxed max-w-3xl border-l-2 border-slate-700 pl-6 py-2",children:t.quote})]}),e.jsx("div",{className:"space-y-4 max-w-3xl",children:t.subjects.map((i,o)=>e.jsx(l,{subject:i},o))})]},t.id))})})]})}export{h as default};
